import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { useAuth } from './AuthContext';
import { wallet } from '../api/wallet'; 
import toast from 'react-hot-toast';

const WalletContext = createContext(null);

export function WalletProvider({ children }) {
  const { user, isAuthenticated } = useAuth();
  const [wallet, setWallet] = useState(null);
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const fetchWallet = useCallback(async () => {
    if (!isAuthenticated || !user?.id) return;
    
    setLoading(true);
    setError(null);
    
    try {
      const res = await wallet.getWallet(user.id);
      setWallet(res.data.data);
    } catch (err) {
      console.error('Failed to fetch wallet:', err);
      setError(err.message || 'Failed to load wallet');
      toast.error('Could not load wallet data');
    } finally {
      setLoading(false);
    }
  }, [isAuthenticated, user?.id]);

  const fetchTransactions = useCallback(async (page = 1, limit = 20) => {
    if (!isAuthenticated || !user?.id) return;
    
    try {
      const res = await walletAPI.getTransactions(user.id, { page, limit });
      setTransactions(res.data.data || []);
    } catch (err) {
      console.error('Failed to fetch transactions:', err);
    }
  }, [isAuthenticated, user?.id]);

  const refreshWallet = useCallback(() => {
    fetchWallet();
    fetchTransactions();
  }, [fetchWallet, fetchTransactions]);

  // Auto-fetch on auth change
  useEffect(() => {
    if (isAuthenticated && user?.id) {
      fetchWallet();
      fetchTransactions();
    } else {
      setWallet(null);
      setTransactions([]);
    }
  }, [isAuthenticated, user?.id, fetchWallet, fetchTransactions]);

  // Poll for pending transactions (optional)
  useEffect(() => {
    if (!isAuthenticated || !wallet?.pendingBalance) return;
    
    const interval = setInterval(() => {
      if (wallet?.pendingBalance > 0) {
        fetchWallet(); // Check if pending cleared
      }
    }, 30000); // Every 30 seconds
    
    return () => clearInterval(interval);
  }, [isAuthenticated, wallet?.pendingBalance, fetchWallet]);

  const value = {
    wallet,
    transactions,
    loading,
    error,
    refreshWallet,
    fetchTransactions
  };

  return (
    <WalletContext.Provider value={value}>
      {children}
    </WalletContext.Provider>
  );
}

export function useWallet() {
  const context = useContext(WalletContext);
  if (!context) {
    throw new Error('useWallet must be used within WalletProvider');
  }
  return context;
}
